%%%%%%%%%% Function fGetRmsV01.m %%%%%%%%%%% get rms, ver.1%% Kei Nakamura% Created on Wednesday, June 6th 2007.% Modified on %% function [rms meanV] = fGetRmsV01(x,cnts)% does analysis on beam.function [rms,meanV] = fGetRmsV01(x,cnts)ttlCnts = sum(cnts); % sum of roweSum = sum(x.*cnts); % E(x)*sume2Sum = sum(x.*x.*cnts); % E(x^2)*sumvSum2 = ttlCnts*e2Sum-eSum^2; % V*sum^2meanV = eSum/ttlCnts;   % E(x)rms = sqrt(vSum2)/ttlCnts;    % std = sqrt(V)
